18	
19	namespace fastertransformer {
20	
21	cublasAlgoMap::cublasAlgoMap(const std::string filename, const std::string sp_config_filename):
22	    config_filename_(filename), sp_config_filename_(sp_config_filename)
23	{
24	    loadGemmConfig();
25	    loadSpGemmConfig();
26	}
27	
28	cublasAlgoMap::cublasAlgoMap(const cublasAlgoMap& algo_map):
29	    config_filename_(algo_map.config_filename_),
30	    sp_config_filename_(algo_map.sp_config_filename_),
31	    algo_map_(algo_map.algo_map_),
32	    sp_algo_map_(algo_map.sp_algo_map_)
33	{
34	}
35	
36	cublasAlgoMap::~cublasAlgoMap()
37	{
38	    algo_map_.clear();
39	}
40	
41	void cublasAlgoMap::loadGemmConfig()
42	{
43	    FILE* fd;
44	    fd = fopen(config_filename_.c_str(), "r");
45	    if (fd == NULL) {
46	        std::cout << "[WARNING] " << config_filename_ << " is not found; using default GEMM algo" << std::endl;
47	        return;
48	    }
49	
50	    int   batchCount2, m2, n2, k2, algoId, customOption, tile, splitK_val;
51	    int   batch_size, seq_len, head_num, size_per_head, dataType;
52	    int   swizzle, reductionScheme, workspaceSize, stages;
53	    int   inner_shapeId, cluster_shapeId, mma_shapeId, cga_shapeId, sche_mode;
54	    float exec_time;
55	    char  tmp[1024];
56	    if (!fgets(tmp, 1024, fd)) {
57	        printf("[ERROR] fgets fail at %s:%d \n", __FILE__, __LINE__);
58	        exit(-1);
59	    }
60	    while (fscanf(fd,
61	                  "%d %d %d %d %d ### %d %d %d %d %d %d %d %d %d %d %d %d "
62	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
63	                  "%d %d "
64	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
65	                  "%d %d %d "
66	#endif
67	                  "%f\n",
68	                  &batch_size,
69	                  &seq_len,
70	                  &head_num,
71	                  &size_per_head,
72	                  &dataType,
73	                  &batchCount2,
74	                  &n2,
75	                  &m2,
76	                  &k2,
77	                  &algoId,
78	                  &customOption,
79	                  &tile,
80	                  &splitK_val,
81	                  &swizzle,
82	                  &reductionScheme,
83	                  &workspaceSize,
84	                  &stages,
85	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
86	                  &inner_shapeId,
87	                  &cluster_shapeId,
88	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
89	                  &mma_shapeId,
90	                  &cga_shapeId,
91	                  &sche_mode,
92	#endif
93	                  &exec_time)
94	           != EOF) {
95	        if (dataType != FLOAT_DATATYPE && dataType != HALF_DATATYPE && dataType != BFLOAT16_DATATYPE
96	            && dataType != INT8_DATATYPE && dataType != FP8_DATATYPE) {
97	            printf("[WARNING][readAlgoFromConfig] wrong dataType %d!\n", dataType);
98	            continue;
99	        }
100	        cublasAlgoConfig_t markStr{batchCount2, m2, n2, k2, static_cast<CublasDataType>(dataType)};
101	        // workspaceSize should be zero
102	        if (algo_map_.find(markStr) == algo_map_.end()) {
103	            algo_map_[markStr].algoId          = algoId;
104	            algo_map_[markStr].customOption    = customOption;
105	            algo_map_[markStr].tile            = tile;
106	            algo_map_[markStr].splitK_val      = splitK_val;
107	            algo_map_[markStr].swizzle         = swizzle;
108	            algo_map_[markStr].reductionScheme = reductionScheme;
109	            algo_map_[markStr].workspaceSize   = workspaceSize;
110	            algo_map_[markStr].stages          = stages;
111	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
112	            algo_map_[markStr].inner_shapeId   = (uint16_t)inner_shapeId;
113	            algo_map_[markStr].cluster_shapeId = (uint16_t)cluster_shapeId;
114	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
115	            algo_map_[markStr].mma_shapeId = (uint16_t)mma_shapeId;
116	            algo_map_[markStr].cga_shapeId = (uint16_t)cga_shapeId;
117	            algo_map_[markStr].sche_mode   = (uint16_t)sche_mode;
118	#endif
119	            algo_map_[markStr].exec_time = exec_time;
120	        }
121	    }
122	    fclose(fd);
123	}
124	
125	bool cublasAlgoMap::isExist(
126	    const int batch_count, const int m, const int n, const int k, const CublasDataType data_type)
127	{
128	    cublasAlgoConfig_t mark{batch_count, n, m, k, data_type};
129	    return algo_map_.find(mark) != algo_map_.end();
130	}
131	
132	cublasLtMatmulAlgo_info
133	cublasAlgoMap::getAlgo(const int batch_count, const int m, const int n, const int k, const CublasDataType data_type)
134	{
135	    cublasAlgoConfig_t mark{batch_count, n, m, k, data_type};
136	    if (algo_map_.find(mark) != algo_map_.end()) {
137	        return algo_map_[mark];
138	    }
139	    else {
140	        cublasLtMatmulAlgo_info tmp_algo;
141	        tmp_algo.algoId =
142	            static_cast<int>(data_type == FLOAT_DATATYPE ? CUBLAS_GEMM_DEFAULT : CUBLAS_GEMM_DEFAULT_TENSOR_OP);
143	        tmp_algo.customOption    = -1;
144	        tmp_algo.tile            = -1;
145	        tmp_algo.splitK_val      = -1;
146	        tmp_algo.swizzle         = -1;
147	        tmp_algo.reductionScheme = -1;
148	        tmp_algo.workspaceSize   = -1;
149	        tmp_algo.stages          = -1;
150	        tmp_algo.exec_time       = -1.0f;
151	        return tmp_algo;
152	    }
153	}
154	
155	void cublasAlgoMap::loadSpGemmConfig()
156	{
157	    if (sp_config_filename_.empty()) {
158	        return;
159	    }
160	    FILE* fd = fopen(sp_config_filename_.c_str(), "r");
161	    if (fd == NULL) {
162	        printf("[WARNING] %s is not found; using SPGEMM algo id 0\n", sp_config_filename_.c_str());
163	        return;
164	    }
165	    sp_algo_map_.clear();
166	    int   batch_size, seq_len, head_num, size_per_head, data_type;
167	    int   batchCount, m, n, k, algoId;
168	    float exec_time;
169	    char  tmp[1024];
170	    if (!fgets(tmp, 1024, fd)) {
171	        printf("[ERROR] fgets fail at %s:%d \n", __FILE__, __LINE__);
172	        exit(-1);
173	    }
174	    while (fscanf(fd,
175	                  "%d %d %d %d %d ### %d %d %d %d %d %f\n",
176	                  &batch_size,
177	                  &seq_len,
178	                  &head_num,
179	                  &size_per_head,
180	                  &data_type,
181	                  &batchCount,
182	                  &m,
183	                  &n,
184	                  &k,
185	                  &algoId,
186	                  &exec_time)
187	           != EOF) {
188	        char mark[256];
189	        sprintf(mark, "%d_%d_%d_%d", batchCount, m, n, k);
190	        std::string markStr(mark);
191	        sp_algo_map_[markStr] = algoId;
192	    }
193	    fclose(fd);
194	}
195	
196	int cublasAlgoMap::getSpAlgo(const int batch_count, const int m, const int n, const int k)
197	{
198	    char mark[256];
199	    sprintf(mark, "%d_%d_%d_%d", batch_count, m, n, k);
200	    if (sp_algo_map_.find(mark) != sp_algo_map_.end()) {
201	        return sp_algo_map_[mark];
202	    }
203	    else {
204	        // for remove padding, select algo 1 for simplicity
205	        return 0;
206	    }
207	}
208	
209	bool cublasAlgoMap::isUseSparse(const int batch_count, const int m, const int n, const int k)
210	{
211	    // not available to use cusparselt.
212	    if (m % 8 != 0 || n % 8 != 0 || k % 8 != 0) {
213	        return false;
214	    }
215	    char mark[256];
216	    sprintf(mark, "%d_%d_%d_%d", batch_count, m, n, k);
217	    if (sp_algo_map_.find(mark) != sp_algo_map_.end()) {
218	        return sp_algo_map_[mark] != -1;
219	    }
220	    else {
221	        // no gemm test case, choose sparse according to sparse flag
222	        return true;
223	    }
224	}
225	
226	}  // namespace fastertransformer
