390	                                          d_A,
391	                                          AType,
392	                                          k,
393	                                          &beta,
394	                                          d_C,
395	                                          CType,
396	                                          n,
397	                                          computeType,
398	                                          static_cast<cublasGemmAlgo_t>(algo));
399	                }
400	                else {
401	                    status = cublasGemmEx(cublas_handle,
402	                                          CUBLAS_OP_N,
403	                                          CUBLAS_OP_N,
404	                                          n,
405	                                          m,
406	                                          k,
407	                                          &alpha,
408	                                          d_B,
409	                                          BType,
410	                                          n,
411	                                          d_A,
412	                                          AType,
413	                                          k,
414	                                          &beta,
415	                                          d_C,
416	                                          CType,
417	                                          n,
418	                                          computeType,
419	                                          static_cast<cublasGemmAlgo_t>(algo));
420	                }
421	
422	                if (status != CUBLAS_STATUS_SUCCESS) {
423	                    break;
424	                }
425	            }
426	            cudaDeviceSynchronize();
427	            gettimeofday(&end, NULL);
428	            if (status == CUBLAS_STATUS_SUCCESS) {
429	                printf("algo_%d costs %.3fms \n", algo, diffTime(start, end) / ites);
430	                if (diffTime(start, end) / ites < exec_time) {
431	                    exec_time = diffTime(start, end) / ites;
432	                    fast_algo = algo;
433	                }
434	            }
435	            sync_check_cuda_error();
436	        }
437	
438	        printf("fast_algo %d costs %.3f ms\n", fast_algo, exec_time);
439	
440	        // for fp16 and bf16, we compare cublasLt
441	        // for fp8, compare cublaslt for all gemm kernels
442	        if ((data_type != FLOAT_DATATYPE && i != 1 && i != 2 && i != 10) || data_type == FP8_DATATYPE) {
443	            printf("***cublasLt Gemm Testing Beign***\n");
444	            // Let try a fixed number of combinations
445	            int                ALGO_COMBINATIONS = 5000;
446	            customMatmulPerf_t perfResults[ALGO_COMBINATIONS];
447	
448	            // for gpt, computeType & scaleType should be FP32
449	            LtHgemmCustomFind<T, float>(ltHandle,
450	                                        batch_size * beam_width,
451	                                        i == 1 || i == 2 ? max_input_len : 1,
452	                                        head_num,
453	                                        size_per_head,
454	                                        n,
455	                                        m,
456	                                        k,
457	                                        &alpha,
458	                                        d_B,
459	                                        d_A,
460	                                        &beta,
461	                                        d_C,
462	                                        cublas_workspace,
463	                                        workSpaceSize,
464	                                        fd,
465	                                        perfResults,
466	                                        ALGO_COMBINATIONS,
467	                                        DType_FP8[i],
468	                                        batchCount[i],
469	                                        strideA[i],
470	                                        strideB[i],
471	                                        strideD[i]);
472	            if (perfResults[0].time < exec_time) {
473	                printPerfStructure(batch_size * beam_width,
474	                                   seq_len,
475	                                   head_num,
476	                                   size_per_head,
477	                                   n,
478	                                   m,
479	                                   k,
480	                                   perfResults[0],
481	                                   fd,
482	                                   data_type,
483	                                   0,
484	                                   batchCount[i]);
485	            }
486	            else {
487	                fprintf(fd,
488	                        "%d %d %d %d %d ### %d %d %d %d %d -1 -1 -1 -1 -1 -1 -1 "
489	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
490	                        "-1 -1 "
491	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
492	                        "-1 -1 -1 "
493	#endif
494	                        "%f\n",
495	                        batch_size * beam_width,
496	                        seq_len,
497	                        head_num,
498	                        size_per_head,
499	                        data_type,
500	                        batchCount[i],
501	                        n,
502	                        m,
503	                        k,
504	                        fast_algo,
505	                        exec_time);
506	            }
507	            printf("***cublasLt Gemm Testing End***\n");
508	        }
509	        else {
510	            fprintf(fd,
511	                    "%d %d %d %d %d ### %d %d %d %d %d -1 -1 -1 -1 -1 -1 -1 "
512	#if (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH >= 3)
513	                    "-1 -1 "
514	#elif (CUBLAS_VER_MAJOR == 11 && CUBLAS_VER_MINOR == 11 && CUBLAS_VER_PATCH < 3)
515	                    "-1 -1 -1 "
516	#endif
517	                    "%f\n",
518	                    batch_size * beam_width,
519	                    seq_len,
520	                    head_num,
521	                    size_per_head,
522	                    data_type,
523	                    batchCount[i],
524	                    n,
525	                    m,
526	                    k,
527	                    fast_algo,
528	                    exec_time);
529	        }
530	        sync_check_cuda_error();
531	        exec_times[i] = exec_time;
532	    }
533	    printf("***cublas Gemm Testing End***\n\n");
534	    fclose(fd);
535	
536	#ifdef SPARSITY_ENABLED
537	    bool do_sparse_test = false;
538	    if (prop.major == 8 && (prop.minor == 0 || prop.minor == 6) && sizeof(T) == sizeof(half)) {
539	        do_sparse_test = true;
540	    }
541	    if (do_sparse_test) {
542	        printf("***cusparseLt Gemm Testing Begin***\n");
543	        // Only first 8 cases can be sparse
544	        // - QKV kernel, Projection, FC1, FC2 in context or decoding.
545	        const int spgemm_num = 8;
546	        if (!isAppend) {
547	            fd = fopen(SPGEMM_CONFIG, "w+");
548	        }
549	        else {
550	            fd = fopen(SPGEMM_CONFIG, "a+");
551	            std::vector<std::string> config;
552	            char                     line[1024];
553	            while (fgets(line, 1024, fd) != NULL) {
554	                config.push_back(std::string(line));
555	            }
556	            line_count = config.size();
557	            // gemm_num configs (cublas/cublasLt), first row is not included
558	            if (config.size() >= (MAX_CONFIG_NUM * spgemm_num + 1)) {
559	                int startIdx = config.size() - ((MAX_CONFIG_NUM - 1) * spgemm_num);
560	                fclose(fd);
561	                fd = fopen(SPGEMM_CONFIG, "w+");
562	                fprintf(fd, "%s", config[0].c_str());
563	                for (uint i = startIdx; i < config.size(); i++) {
564	                    fprintf(fd, "%s", config[i].c_str());
565	                }
566	                line_count = config.size() - (spgemm_num + 3);
567	            }
568	        }
569	        if (line_count == 0) {
570	            // header line
571	            fprintf(fd,
572	                    "batch_size, seq_len, head_num, size_per_head dataType "
573	                    "### batchCount, m, n, k, algoId, exec_time\n");
574	        }
575	
576	        cusparseLtHandle_t handle;
577	        CHECK_CUSPARSE(cusparseLtInit(&handle));
578	        cusparseOrder_t     order = CUSPARSE_ORDER_COL;
579	        cusparseOperation_t opA   = CUSPARSE_OPERATION_NON_TRANSPOSE;
580	        cusparseOperation_t opB   = CUSPARSE_OPERATION_NON_TRANSPOSE;
581	        // let's make this optional
582	        cusparseComputeType compute_type = CUSPARSE_COMPUTE_16F;
583	        unsigned            alignment    = 16;
584	        cudaStream_t        stream       = 0;
585	        float               alpha2       = 1.0f;
586	        float               beta2        = 0.0f;
587	        for (int i = 0; i < gemm_num; ++i) {
588	            // skip qk or attn or logit gemms.
589	            if (i == 1 || i == 2 || i == 10) {
590	                continue;
591	            }
592	
593	            // seq_len is always 1 except context gemms.
594	            int seq_len = i <= 5 ? max_input_len : 1;
595	
596	            // to be compatible with spgemm wrapper, we let A be the weight matrix
597	            // so m and n are swapped
598	            // A: mxk B: kxn C:mxn
599	            int m = N[i], n = M[i], k = K[i];
600	            printf("\n-----------------------------\n");
601	            printf("GEMM test %d: [M: %d, K: %d, N: %d]\n", i, m, k, n);
602	
603	            if (n % 8 != 0) {
604	                n = div_up(n, 8) * 8;  // pad n to be multiple of 8 as FT does.
605	            }
606	
607	            T* d_A = (T*)buffer;
608	            T* d_B = d_A + m * k * batchCount[i];
609	            T* d_C = d_B + k * n * batchCount[i];
610	            T* dA_compressed;
611	            {
612	                cusparseLtMatDescriptor_t matA;
613	                CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(
614	                    &handle, &matA, m, k, m, alignment, CUDA_R_16F, order, CUSPARSELT_SPARSITY_50_PERCENT))
615	                CHECK_CUSPARSE(
616	                    cusparseLtSpMMAPrune2(&handle, &matA, true, opA, d_A, d_A, CUSPARSELT_PRUNE_SPMMA_STRIP, stream))
617	                size_t compressed_size;
618	                CHECK_CUSPARSE(cusparseLtSpMMACompressedSize2(&handle, &matA, &compressed_size))
619	                check_cuda_error(cudaMalloc((void**)&dA_compressed, compressed_size));
620	                CHECK_CUSPARSE(cusparseLtSpMMACompress2(&handle, &matA, true, opA, d_A, dA_compressed, stream))
621	            }
622	
623	            float exec_time = 99999.0f;
624	            int   fast_algo = 0;
625	            if (isSparseGemmAvailable(m, n, k)) {
626	                for (int alg = 0; alg < 4; ++alg) {
627	                    cudaDeviceSynchronize();
628	                    cusparseLtMatDescriptor_t matA, matB, matC;
629	                    void*                     d_workspace = nullptr;
630	                    int                       num_streams = 1;
631	                    cudaStream_t              streams[1]  = {stream};
632	                    CHECK_CUSPARSE(cusparseLtStructuredDescriptorInit(
633	                        &handle, &matA, m, k, m, alignment, CUDA_R_16F, order, CUSPARSELT_SPARSITY_50_PERCENT))
634	                    CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(&handle, &matB, k, n, k, alignment, CUDA_R_16F, order))
635	                    CHECK_CUSPARSE(cusparseLtDenseDescriptorInit(&handle, &matC, m, n, m, alignment, CUDA_R_16F, order))
636	                    cudaDeviceSynchronize();
637	                    gettimeofday(&start, NULL);
638	                    for (int ite = 0; ite < ites; ++ite) {
639	                        // initializing MatDesc takes a lot of time
640	                        // and these descs can be stored to other place
641	                        // whereas storing MatMulPlan to other place will cause errors
642	                        cusparseLtMatmulDescriptor_t   matmul;
643	                        cusparseLtMatmulAlgSelection_t alg_sel;
644	                        cusparseLtMatmulPlan_t         plan;
645	                        CHECK_CUSPARSE(cusparseLtMatmulDescriptorInit(
646	                            &handle, &matmul, opA, opB, &matA, &matB, &matC, &matC, compute_type))
647	                        CHECK_CUSPARSE(
648	                            cusparseLtMatmulAlgSelectionInit(&handle, &alg_sel, &matmul, CUSPARSELT_MATMUL_ALG_DEFAULT))
649	                        CHECK_CUSPARSE(cusparseLtMatmulAlgSetAttribute(
650	                            &handle, &alg_sel, CUSPARSELT_MATMUL_ALG_CONFIG_ID, &alg, sizeof(alg)))
651	                        size_t workspace_size;
652	                        CHECK_CUSPARSE(cusparseLtMatmulGetWorkspace(&handle, &alg_sel, &workspace_size))
653	                        CHECK_CUSPARSE(cusparseLtMatmulPlanInit(&handle, &plan, &matmul, &alg_sel, workspace_size))
654	                        CHECK_CUSPARSE(cusparseLtMatmul(&handle,
655	                                                        &plan,
656	                                                        &alpha2,
657	                                                        dA_compressed,
658	                                                        d_B,
659	                                                        &beta2,
660	                                                        d_C,
661	                                                        d_C,
662	                                                        d_workspace,
663	                                                        streams,
664	                                                        num_streams))
665	                        CHECK_CUSPARSE(cusparseLtMatmulPlanDestroy(&plan))
666	                    }
667	                    cudaDeviceSynchronize();
668	                    gettimeofday(&end, NULL);
669	                    printf("algo_%d costs %.3fms \n", alg, diffTime(start, end) / ites);
670	                    if (diffTime(start, end) < exec_time) {
671	                        exec_time = diffTime(start, end);
672	                        fast_algo = alg;
673	                    }
674	                }
675	            }
676	            exec_time /= ites;
677	            if (exec_time >= exec_times[i]) {
678	                fast_algo = -1;
679	            }
680	            printf("fast_algo %d\n", fast_algo);
681	            fprintf(fd,
682	                    "%d %d %d %d %d ### %d %d %d %d %d %f\n",
683	                    batch_size * beam_width,
684	                    seq_len,
685	                    head_num,
686	                    size_per_head,
687	                    data_type,
688	                    batchCount[i],
689	                    m,
690	                    n,
691	                    k,
692	                    fast_algo,
693	                    exec_time);
694	            cudaFree(dA_compressed);
695	        }
696	        CHECK_CUSPARSE(cusparseLtDestroy(&handle))
697	        fclose(fd);
698	        printf("***cusparseLt Gemm Testing End***\n");
699	    }
700	#endif
701	
702	    printf("***GPT Gemm Testing End***\n");
703	    return;
704	}
