718	                                             int   beam_width,
719	                                             int   max_input_len,
720	                                             int   head_num,
721	                                             int   size_per_head,
722	                                             int   inter_size,
723	                                             int   vocab_size,
724	                                             int   tensor_para_size,
725	                                             void* buffer_in,
726	                                             bool  isAppend);
