730	                                                      int   beam_width,
731	                                                      int   max_input_len,
732	                                                      int   head_num,
733	                                                      int   size_per_head,
734	                                                      int   inter_size,
735	                                                      int   vocab_size,
736	                                                      int   tensor_para_size,
737	                                                      void* buffer_in,
738	                                                      bool  isAppend);
739	#endif
