741	#ifdef ENABLE_FP8
742	template void generate_gpt_gemm_config<__nv_fp8_e4m3>(int   batch_size,
743	                                                      int   beam_width,
744	                                                      int   max_input_len,
745	                                                      int   head_num,
746	                                                      int   size_per_head,
747	                                                      int   inter_size,
748	                                                      int   vocab_size,
749	                                                      int   tensor_para_size,
750	                                                      void* buffer_in,
751	                                                      bool  isAppend);
752	#endif
753	
754	size_t calGptGemmTestBufSizeInByte(size_t         batch_size,
755	                                   size_t         beam_width,
756	                                   size_t         max_input_len,
757	                                   size_t         head_num,
758	                                   size_t         size_per_head,
759	                                   size_t         inter_size,
760	                                   size_t         vocab_size,
761	                                   size_t         tensor_para_size,
762	                                   CublasDataType data_type)
763	{
764	    size_t       buf_size_in_byte   = 0;
765	    const size_t hidden_units       = head_num * size_per_head;
766	    const size_t local_head_num     = head_num / tensor_para_size;
767	    const size_t local_hidden_units = local_head_num * size_per_head;
768	
769	    // int wordSize = (data_type == FLOAT_DATATYPE ? sizeof(float) : sizeof(half));
770	    // Because we always use float for some buffer, set the wordSize to float directly.
771	    int wordSize = sizeof(float);
772	
773	    size_t              m = batch_size * beam_width * max_input_len;
774	    std::vector<size_t> buff_size;
775	    // for context qkv gemm
776	    buff_size.push_back(m * hidden_units + hidden_units * 3 * local_hidden_units + m * 3 * local_hidden_units);
777	    // for context batch gemm
778	    buff_size.push_back(m * local_hidden_units + m * local_hidden_units
779	                        + batch_size * beam_width * head_num * max_input_len * max_input_len);
780	    // for context ffn gemm
781	    buff_size.push_back(m * inter_size / tensor_para_size + hidden_units * inter_size / tensor_para_size
782	                        + m * hidden_units);
783	    // for vocab
784	    buff_size.push_back(m * hidden_units + hidden_units * ceil(vocab_size / 8.) * 8 / tensor_para_size
785	                        + m * ceil(vocab_size / 8.) * 8 / tensor_para_size);
786	
787	    for (auto t : buff_size) {
788	        buf_size_in_byte = buf_size_in_byte > t ? buf_size_in_byte : t;
789	    }
790	    buf_size_in_byte *= wordSize;
791	    buf_size_in_byte += ((data_type == HALF_DATATYPE || data_type == BFLOAT16_DATATYPE || data_type == FP8_DATATYPE) ?
792	                             CUBLAS_WORKSPACE_SIZE :
793	                             0);
794	
795	    return buf_size_in_byte;
796	}
